export const dynamic = "force-dynamic";

export default async function AdminLoginPage({ searchParams }: { searchParams: Promise<{ error?: string; return_to?: string }> }) {
  const params = await searchParams;
  const returnTo = params.return_to?.startsWith("/") && !params.return_to.startsWith("//") ? params.return_to : "/yonetim";
  return <main className="admin-shell admin-login">
    <section className="admin-login-card">
      <p className="eyebrow"><span>UH</span>Güvenli yönetim</p>
      <h1>Yönetim girişi</h1>
      <p>İçerik, proje, referans ve site ayarlarını düzenlemek için giriş yapın.</p>
      {params.error && <p className="admin-notice">E-posta adresi veya parola hatalı.</p>}
      <form action="/api/admin/login" method="post">
        <input type="hidden" name="return_to" value={returnTo} />
        <label>E-posta<input name="email" type="email" autoComplete="username" required /></label>
        <label>Parola<input name="password" type="password" autoComplete="current-password" required /></label>
        <button type="submit">Giriş yap</button>
      </form>
    </section>
  </main>;
}
